import { NextResponse } from "next/server";
import path from "path";
import fs from "fs-extra";
import poppler from "pdf-poppler";
import { IncomingForm } from "formidable";

export const config = {
  api: {
    bodyParser: false, // Disable default body parser for Formidable
  },
};
// Removed the module augmentation as it is not allowed for untyped modules.

export async function POST(req: Request) {
  try {
    // Parse the uploaded file
    const form = new IncomingForm({ multiples: false });
    const [fields, files] = await form.parse(req);

    if (!files.file) {
      return NextResponse.json({ error: "No file uploaded" }, { status: 400 });
    }

    const file = files.file[0]; // Get the uploaded file
    const tempFilePath = file.filepath; // Temporary storage
    const fileName = file.originalFilename;

    // Define save path
    const uploadDir = path.join(process.cwd(), "public/uploads");
    await fs.ensureDir(uploadDir); // Ensure directory exists
    const pdfPath = path.join(uploadDir, fileName);

    // Move the file to uploads folder
    await fs.move(tempFilePath, pdfPath);

    // Convert PDF to images
    const images = await convertPDFToImages(pdfPath);

    return NextResponse.json({ message: "PDF uploaded successfully", images });
  } catch (error) {
    console.error("Error:", error);
    return NextResponse.json(
      { error: "Failed to upload PDF" },
      { status: 500 }
    );
  }
}

// Function to convert PDF to images
async function convertPDFToImages(pdfPath: string) {
  const outputDir = path.dirname(pdfPath); // Use the same directory as PDF
  const outputPrefix = path.basename(pdfPath, ".pdf"); // Extract file name

  const options = {
    format: "png",
    out_dir: outputDir,
    out_prefix: outputPrefix,
    scale: 1024, // Image resolution
  };

  try {
    await poppler.convert(pdfPath, options);
    const imageFiles = await fs.readdir(outputDir);
    return imageFiles.filter((file) => file.startsWith(outputPrefix));
  } catch (error) {
    console.error("Poppler error:", error);
    return [];
  }
}
